import{_ as i}from"./plugin-vue_export-helper-c27b6911.js";import{r as o,o as t,c as h,b as e,d as a,e as n,a as c}from"./app-99b09319.js";const s="/blog/assets/1711526206795-154d403b.png",d={},l={href:"https://zhuanlan.zhihu.com/p/71156910",target:"_blank",rel:"noopener noreferrer"},p={href:"https://tech.meituan.com/2018/11/15/java-lock.html",target:"_blank",rel:"noopener noreferrer"},_=c('<h2 id="_0-java中的两种锁" tabindex="-1"><a class="header-anchor" href="#_0-java中的两种锁" aria-hidden="true">#</a> 0.Java中的两种锁</h2><ul><li>synchronized，关键字，在jvm中实现</li><li>Lock，一个接口</li></ul><h3 id="_0-1-synchronized" tabindex="-1"><a class="header-anchor" href="#_0-1-synchronized" aria-hidden="true">#</a> 0.1 synchronized</h3><p>synchronized是Java中的一个关键字</p><p>它是一个悲观锁，它涉及了一些锁升级的概念。</p><ul><li>在最开始时，synchronized是偏向锁，即它更加偏向于第一个获取到这个锁的线程。如果说下一次执行到同步语句，发现还是这个线程，那么synchronized就不需要重新加锁了，这样只有一个线程的话，就不需要频繁加锁，性能开销基本没有。</li><li>如果某时刻又来了一个线程，那么此时的偏向锁就会升级为轻量锁。轻量级锁是一个自旋锁，如果现在有两个线程A和B，那么A在执行的时候，B此时会自旋等待，即不会暂停执行。这个自旋等待次数是有上限的，一旦到达了某个上限，就会升级为重量级锁，此时没有争夺到锁的线程就会暂停执行，让出CPU，直到通知它再次执行。</li></ul><p><img src="'+s+'" alt="1711526206795"></p><h2 id="_1-乐观锁和悲观锁" tabindex="-1"><a class="header-anchor" href="#_1-乐观锁和悲观锁" aria-hidden="true">#</a> 1.乐观锁和悲观锁</h2><p>对于乐观锁来说，它会认为每次读取都不会有其他线程去修改，就直接读就可以了。对于写的时候，它会比较当前值是否是期待值，如果是，则表明可能没有其他线程修改，就进行修改，否则则循环等待下次修改。</p><p>对于悲观锁来说，它认为每次读取都会有人修改，所以就在读取之前都加锁。这样在竞争激烈的情况下可能导致性能下降。</p><p>乐观锁更加适合读多写少的情况，而悲观锁更适合写多的情况</p><h3 id="_1-1-乐观锁有什么问题" tabindex="-1"><a class="header-anchor" href="#_1-1-乐观锁有什么问题" aria-hidden="true">#</a> 1.1 乐观锁有什么问题？</h3><p>乐观锁一般使用CAS来实现。</p><p>使用CAS时，可能会有三个问题：</p><ul><li>可能会导致ABA问题，即其他线程把数据从A修改到B，又从B修改到A，这时我们的线程是发现不了数据变化的</li><li>在写多的场景下，CAS会频繁失败然后循环等待，这时也是比较耗时的。</li><li>CAS只能保证单个共享变量的原子性，没办法保证多个共享变量的原子性</li></ul><h3 id="_1-2-java中哪些实现是悲观锁-哪些是乐观锁" tabindex="-1"><a class="header-anchor" href="#_1-2-java中哪些实现是悲观锁-哪些是乐观锁" aria-hidden="true">#</a> 1.2 Java中哪些实现是悲观锁，哪些是乐观锁</h3><p>Java中，无论是synchronized还是Lock接口，都是悲观锁。</p><p>Java中乐观锁可以使用Unsafe的CAS，还有一些原子类都是乐观锁</p><h2 id="_2-自旋锁" tabindex="-1"><a class="header-anchor" href="#_2-自旋锁" aria-hidden="true">#</a> 2.自旋锁</h2><p>自旋锁就是一个线程在CPU执行时，发现同步资源是上锁的，此时不必让出CPU，而是在CPU中自旋等待，等待到同步资源解锁直接开始执行就可以了。</p><p>因为自旋锁不会让出CPU，等待线程会在CPU中无用的自旋操作，所以会有一定的上限，如果自旋次数超过某个数量，就不再自旋了。</p><p>此外，后面还引入了自适应自旋锁，即自旋次数不再固定，而是根据历史的自旋次数等因素来动态决定。</p><h2 id="_3-公平锁和非公平锁" tabindex="-1"><a class="header-anchor" href="#_3-公平锁和非公平锁" aria-hidden="true">#</a> 3.公平锁和非公平锁</h2><ul><li>公平锁：按照线程队列的顺序来获取锁，只有队头的线程才可以获得锁</li><li>非公平锁：队列中的线程都可以竞争锁，会出现后来的线程却先得到锁的情况，也可以不进队列直接执行。<strong>非公平锁可以提高性能，因为有时候线程不必经历暂停-恢复的过程</strong>，但是可能出现线程饿死的情况。</li></ul><p><strong>公平锁就是线程直接进入阻塞队列，直到成为队列的第一个，才可以获得锁。非公平锁就是多个线程加锁时直接尝试上锁，上锁成功直接执行，失败进入阻塞队列。</strong></p><p>ReentrantLock默认的实现就是非公平锁。<strong>它其中有一个Sync类，继承了AQS</strong>，它有两个子类FairSync和NonfairSync，对应着公平锁和非公平锁。</p><h2 id="_4-可重入锁-非可重入锁" tabindex="-1"><a class="header-anchor" href="#_4-可重入锁-非可重入锁" aria-hidden="true">#</a> 4.可重入锁，非可重入锁</h2><p><strong>可重入锁又叫递归锁，就是如果一个线程在外部方法已经获取了锁，那么在进入内部方法时，会自动获得锁，而不会被阻塞</strong>。</p><p>可重入锁可以防止死锁。</p><p>synchronized和ReentrintLock都是可重入锁。</p><p>如何实现的？</p>',31);function u(f,m){const r=o("ExternalLinkIcon");return t(),h("div",null,[e("p",null,[a("总结于"),e("a",l,[a("文章1"),n(r)]),a(),e("a",p,[a("文章2"),n(r)])]),_])}const b=i(d,[["render",u],["__file","lock.html.vue"]]);export{b as default};
